import { Request, Response, NextFunction } from "express";
import type { CastError } from "mongoose";
import { databaseErrorConverter } from "@utils/helpers-errors";
import type { SearchProductsRequest } from "@api/api";
import ProductService from "@services/products";

/**
 * Url parameters generated by the search form (they are the same)
 */
export type IGetAllProductsQuery = Partial<Record<keyof SearchProductsRequest, string>>;

/**
 * Get all products
 * TODO page is not in the query but in the parameter!
 *
 * @param request
 * @param response
 * @param next
 */
export const pageAllProducts = async (
    // Page can be param or query
    request: Request<{ page?: string }, unknown, unknown, IGetAllProductsQuery>,  // fourth generic = query
    response: Response,
    next: NextFunction
) =>
    ProductService.search(
        {
            ...request.query,
            minPrice: request.query?.minPrice ? Number.parseInt(request.query.minPrice) : undefined,
            maxPrice: request.query?.maxPrice ? Number.parseInt(request.query.maxPrice) : undefined,
            page: Number.parseInt(request.params.page ?? request.query.page ?? "1"),
            pageSize: Number.parseInt(process.env.NODE_SETTINGS_PAGINATION_PAGE_SIZE ?? "10"),
        },
        request.session.user?.admin
    )
        .then(async ({ items, meta }) =>
            response.render('products/list', {
                pageMetaTitle: 'All Products',
                pageMetaLinks: [
                    "/css/product.css"
                ],
                productList: items,
                itemsTotal: meta.totalItems,
                pageCurrent: meta.page,
                pageTotal: meta.totalPages,
                search: request.query,
            })
        )
        .catch((error: Error | CastError) => next(databaseErrorConverter(error)));